import React from 'react';

const Content = ({ items, handleChange, changeDelete }) => {
  return (
    <main>{(items.length) ? (<Content items={items} changeDelete={changeDelete} handleChange={handleChange}/>) : <p>Done All Activity Quickly</p>}
    </main>
  );
};

export default Content;
